17	const isBlockOfThreeAlike = (items: Item[]): boolean =>
18	  items.length === BLOCK_SIZE && items.every((item) => item.type === items[0].type);
19	
20	const sumOfBasePremiums = (items: Item[]): number =>
21	  items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
22	
23	const basePremiumFor = (items: Item[]): number =>
24	  isBlockOfThreeAlike(items) ? BLOCK_PREMIUM : sumOfBasePremiums(items);
25	
26	const quotePremium = (base: number): number =>
27	  Math.ceil(base + base * FIRST_INSURANCE_RATE + PROCESSING_FEE);
28	
29	export const runScenario = (scenario: any): unknown => {
30	  const base = basePremiumFor(scenario.steps[0].items);
31	  return { results: [{ premium: quotePremium(base) }] };
32	};
